def etiqueta_bug(x):
    if x >= 0:
        return "no-negativo"
    elif x > 0:  # rama muerta: si x>0 ya entró en x>=0
        return "positivo"
    return "negativo"

print("La rama elif x > 0 nunca corre porque x>=0 la cubre antes")
for x in [5, 0, -2]:
    print("bug", x, etiqueta_bug(x))

def etiqueta_ok(x):
    if x > 0:
        return "positivo"
    elif x == 0:
        return "cero"
    else:
        return "negativo"

for x in [5, 0, -2]:
    print("ok", x, "→", etiqueta_ok(x))

