    print(s, r, "→", decide(s, r))

def validate_contacto(c):
    if c is None:
        return "review"
    if not isinstance(c, str) or not c.strip():
        return "reject"
    digits = c.strip()
    if not digits.isdigit() or len(digits) != 9:
        return "reject"
    return "accept"

for c in [None, "", "999000111", "123", "99a000111"]:
    print(repr(c), "→", validate_contacto(c))

def check_invariants(rec):
    errors = []
    edad = rec.get("edad")
    if edad is not None:
        if not isinstance(edad, int) or not (0 <= edad <= 120):
            errors.append("edad viola invariante int 0-120")
    ALLOWED = {"Lima", "Arequipa", "Cusco"}
    reg = rec.get("region")
    if reg is not None and reg not in ALLOWED:
        errors.append("region fuera de allowlist")
    return errors

print(check_invariants({"edad": 34, "region": "Lima"}))
print(check_invariants({"edad": -1, "region": "Tacna"}))

def validate_edad_msg(edad):
    if edad is None:
        return {"status": "review", "code": "MISSING",
                "message": "Campo 'edad' ausente: envía un entero 0–120 o márcalo para review."}
    if not isinstance(edad, int):
        return {"status": "reject", "code": "BAD_TYPE",
                "message": f"Campo 'edad'={edad!r} no es int; corrige el tipo."}
    if edad < 0 or edad > 120:
        return {"status": "reject", "code": "OUT_OF_RANGE",
                "message": f"Campo 'edad'={edad} fuera de rango; usa 0–120."}
    return {"status": "accept", "code": "OK", "message": "ok"}

for e in [None, "x", -5, 30]:
    print(validate_edad_msg(e))

